"use client";

import { useEffect, useState } from "react";
import { Vendor } from "@/types";
import { getVendors, addVendor } from "@/lib/vendors";

export default function VendorsPage() {
    const [vendors, setVendors] = useState<Vendor[]>([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);

    // Form State
    const [formData, setFormData] = useState({
        name: "",
        contactName: "",
        email: "",
        phone: "",
        address: "",
        taxId: "",
    });

    const fetchVendors = async () => {
        setLoading(true);
        const data = await getVendors();
        setVendors(data);
        setLoading(false);
    };

    useEffect(() => {
        fetchVendors();
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            await addVendor({
                ...formData,
                status: 'ACTIVE'
            });
            setIsModalOpen(false);
            setFormData({ name: "", contactName: "", email: "", phone: "", address: "", taxId: "" });
            fetchVendors(); // Refresh list
        } catch (error: any) {
            console.error("Full error:", error);
            alert(`Error adding vendor: ${error.message || error.code || "Unknown error"}`);
        }
    };

    return (
        <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <h1 style={{ fontSize: '1.875rem', fontWeight: 'bold', color: 'var(--primary)' }}>Vendor Management</h1>
                <button className="btn btn-primary" onClick={() => setIsModalOpen(true)}>
                    + Add Vendor
                </button>
            </div>

            {loading ? (
                <p>Loading vendors...</p>
            ) : vendors.length === 0 ? (
                <div className="card" style={{ textAlign: 'center', padding: '3rem' }}>
                    <p style={{ color: 'var(--text-secondary)' }}>No vendors found. Add your first vendor to get started.</p>
                </div>
            ) : (
                <div className="card" style={{ overflowX: 'auto', padding: 0 }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
                        <thead style={{ backgroundColor: 'var(--background)', borderBottom: '1px solid var(--border)' }}>
                            <tr>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Company Name</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Contact Person</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Email</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Status</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            {vendors.map((vendor) => (
                                <tr key={vendor.id} style={{ borderBottom: '1px solid var(--border)' }}>
                                    <td style={{ padding: '1rem', fontWeight: 500 }}>{vendor.name}</td>
                                    <td style={{ padding: '1rem' }}>{vendor.contactName}</td>
                                    <td style={{ padding: '1rem' }}>{vendor.email}</td>
                                    <td style={{ padding: '1rem' }}>
                                        <span style={{
                                            padding: '0.25rem 0.5rem',
                                            borderRadius: '999px',
                                            fontSize: '0.75rem',
                                            backgroundColor: vendor.status === 'ACTIVE' ? '#dcfce7' : '#fee2e2',
                                            color: vendor.status === 'ACTIVE' ? '#166534' : '#991b1b'
                                        }}>
                                            {vendor.status}
                                        </span>
                                    </td>
                                    <td style={{ padding: '1rem' }}>
                                        <button style={{ color: 'var(--accent)', background: 'none', border: 'none', cursor: 'pointer' }}>Edit</button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}

            {/* Simple Modal Implementation */}
            {isModalOpen && (
                <div style={{
                    position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
                    backgroundColor: 'rgba(0,0,0,0.5)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 50
                }}>
                    <div className="card" style={{ width: '500px', maxWidth: '90%' }}>
                        <h2 style={{ fontSize: '1.5rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>Add New Vendor</h2>
                        <form onSubmit={handleSubmit}>
                            <div style={{ display: 'grid', gap: '1rem' }}>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.875rem', marginBottom: '0.5rem' }}>Company Name *</label>
                                    <input required type="text" style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.875rem', marginBottom: '0.5rem' }}>Contact Name *</label>
                                    <input required type="text" style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.contactName} onChange={e => setFormData({ ...formData, contactName: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.875rem', marginBottom: '0.5rem' }}>Email *</label>
                                    <input required type="email" style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.email} onChange={e => setFormData({ ...formData, email: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.875rem', marginBottom: '0.5rem' }}>Phone</label>
                                    <input type="tel" style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.phone} onChange={e => setFormData({ ...formData, phone: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.875rem', marginBottom: '0.5rem' }}>Tax ID</label>
                                    <input type="text" style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.taxId} onChange={e => setFormData({ ...formData, taxId: e.target.value })} />
                                </div>
                            </div>
                            <div style={{ marginTop: '2rem', display: 'flex', justifyContent: 'flex-end', gap: '0.5rem' }}>
                                <button type="button" className="btn" style={{ border: '1px solid var(--border)' }} onClick={() => setIsModalOpen(false)}>Cancel</button>
                                <button type="submit" className="btn btn-primary">Save Vendor</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
